import React, { useState } from "react";
import { useNavigate, NavLink } from "react-router-dom";
import { register } from "../../services/userService";

function Registration() {
  // Khai báo state formData để lưu thông tin người dùng nhập
  const [formData, setFormData] = useState({
    fullName: "",
    username: "",
    password: "",
    confirmPassword: "",
    role: "",
  });

  const navigate = useNavigate();

  // Hàm xử lý cập nhật state khi người dùng nhập vào các trường
  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData({
      ...formData,
      [name]: value, // Cập nhật đúng trường dữ liệu tương ứng với name của input
    });
  };

  // Hàm xử lý submit form đăng ký
  const handleSubmit = async (e) => {
    e.preventDefault();

    // Kiểm tra xác nhận mật khẩu
    if (formData.password !== formData.confirmPassword) {
      alert("Mật khẩu xác nhận không khớp!");
      return;
    }

    try {
      // Gửi dữ liệu form đến API
      const response = await register({
        name: formData.fullName,
        username: formData.username,
        password: formData.password,
        role: formData.role,
      });

      // Kiểm tra phản hồi từ API
      if (response.message === "Đăng ký thành công!") {
        alert("Đăng ký thành công!");
        navigate("/login2"); // Chuyển đến trang đăng nhập
      } else {
        alert("Đăng ký thất bại: " + response.message);
      }
    } catch (error) {
      console.error("Đăng ký thất bại:", error.message);
      alert("Đăng ký thất bại: " + error.message);
    }
  };

  return (
    <div className="general">
      <div className="register-form">
        <h2>Đăng ký</h2>
        <form onSubmit={handleSubmit}>
          <input
            type="text"
            name="fullName"
            placeholder="Nhập họ và tên"
            value={formData.fullName}
            onChange={handleChange} // Cập nhật state khi nhập
            required
          />
          <input
            type="text"
            name="username"
            placeholder="Username"
            value={formData.username}
            onChange={handleChange} // Cập nhật state khi nhập
            required
          />
          <input
            type="password"
            name="password"
            placeholder="Password"
            value={formData.password}
            onChange={handleChange} // Cập nhật state khi nhập
            required
          />
          <input
            type="password"
            name="confirmPassword"
            placeholder="Confirm Password"
            value={formData.confirmPassword}
            onChange={handleChange} // Cập nhật state khi nhập
            required
          />
          <input
            type="text"
            name="role"
            placeholder="Role"
            value={formData.role}
            onChange={handleChange} // Cập nhật state khi nhập
            required
          />
          <button type="submit" className="btn">
            Register
          </button>
          <NavLink to="/" className="btn-close">
            Close
          </NavLink>
          <p
            onClick={() => navigate("/login2")}
            className="btn-text"
            style={{ cursor: "pointer" }}
          >
            Bạn đã có tài khoản?
          </p>
        </form>
      </div>
    </div>
  );
}

export default Registration;
